5	
6	//! Host-side loading for embedded device artifact bundles.
7	
8	use crate::ltoir;
9	pub use cuda_core::embedded::{
10	    ArtifactPayloadKind, EmbeddedModule, OwnedArtifactBundle, artifact_bundles_from_binary_path,
11	    artifact_bundles_from_current_exe, embedded_modules_from_current_exe,
12	};
13	use cuda_core::{CudaContext, CudaModule, DriverError};
14	use std::sync::Arc;
15	use thiserror::Error;
16	
17	/// Errors while discovering, building, or loading an embedded CUDA module.
18	#[derive(Debug, Error)]
19	pub enum EmbeddedModuleError {
20	    /// Reading the embedded artifact section failed.
21	    #[error(transparent)]
22	    Core(#[from] cuda_core::EmbeddedModuleError),
23	
24	    /// The named bundle was not present in the current executable.
25	    #[error("embedded CUDA module '{name}' was not found")]
26	    ModuleNotFound { name: String },
27	
28	    /// No embedded bundles with loadable payloads were found.
29	    #[error("no embedded CUDA modules were found")]
30	    NoModules,
31	
32	    /// A bundle existed, but it contained no supported payload.
33	    #[error("embedded CUDA module '{name}' has no supported payload")]
34	    UnsupportedPayload { name: String },
35	
36	    /// NVVM IR or LTOIR payload compilation failed.
37	    #[error("failed to build embedded CUDA module: {0}")]
38	    Ltoir(#[from] ltoir::LtoirError),
39	
40	    /// The CUDA driver rejected the selected module image.
41	    #[error("failed to load embedded CUDA module: {0}")]
42	    Driver(#[from] DriverError),
43	}
44	
45	/// Load a named embedded artifact bundle from the current executable.
46	///
47	/// Cubin and PTX payloads are loaded directly with the CUDA driver. NVVM IR and
48	/// LTOIR payloads are linked to an in-memory cubin for their original target.
49	/// A payload built for a standard pre-Blackwell target, such as `sm_86`, may
50	/// instead be converted to PTX and JIT-compiled by the driver on Blackwell.
51	pub fn load_embedded_module(
52	    ctx: &Arc<CudaContext>,
53	    name: &str,
54	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
55	    let bundle = artifact_bundles_from_current_exe()?
56	        .into_iter()
57	        .find(|bundle| bundle.name == name)
58	        .ok_or_else(|| EmbeddedModuleError::ModuleNotFound {
59	            name: name.to_string(),
60	        })?;
61	    load_bundle(ctx, &bundle)
62	}
63	
64	/// Merge all PTX bundles from the current executable into a single CUDA module.
65	///
66	/// When a generic kernel is monomorphized in a consuming crate, its PTX ends
67	/// up in that crate's bundle rather than the defining crate's bundle. This
68	/// function gathers every PTX bundle in the binary, strips duplicate header
69	/// directives (`.version`, `.target`, `.address_size`) from all but the first
70	/// bundle, concatenates the bodies, and loads the result as one CUDA module.
71	/// All kernel symbols are therefore available regardless of which crate bundle
72	/// they were compiled into.
73	///
74	/// Bundles with non-PTX payloads (NVVM IR, LTOIR, cubin) are skipped; use
75	/// `load_embedded_module` for those.
76	pub fn load_all_ptx_bundles_merged(
77	    ctx: &Arc<CudaContext>,
78	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
79	    let bundles = artifact_bundles_from_current_exe()?;
80	
81	    let mut merged = String::new();
82	    let mut found_any = false;
83	
84	    for bundle in &bundles {
85	        if let Some(ptx_bytes) = bundle.payload(ArtifactPayloadKind::Ptx) {
86	            let ptx_str = std::str::from_utf8(ptx_bytes)
87	                .map_err(|_| EmbeddedModuleError::UnsupportedPayload {
88	                    name: bundle.name.clone(),
89	                })?
90	                .trim_end_matches('\0');
91	
92	            if !found_any {
93	                merged.push_str(ptx_str);
94	                merged.push('\n');
95	                found_any = true;
96	            } else {
97	                // Strip per-file header directives; only one set is valid in a
98	                // concatenated PTX module.
99	                for line in ptx_str.lines() {
100	                    let trimmed = line.trim_start();
101	                    if trimmed.starts_with(".version")
102	                        || trimmed.starts_with(".target")
103	                        || trimmed.starts_with(".address_size")
104	                    {
105	                        continue;
106	                    }
107	                    merged.push_str(line);
108	                    merged.push('\n');
109	                }
110	            }
111	        }
112	    }
113	
114	    if !found_any {
115	        return Err(EmbeddedModuleError::NoModules);
116	    }
117	
118	    Ok(ctx.load_module_from_image(merged.as_bytes())?)
119	}
120	
121	/// Load the first embedded artifact bundle with a supported payload.
122	pub fn load_first_embedded_module(
123	    ctx: &Arc<CudaContext>,
124	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
125	    for bundle in artifact_bundles_from_current_exe()? {
126	        match load_bundle(ctx, &bundle) {
127	            Ok(module) => return Ok(module),
128	            Err(EmbeddedModuleError::UnsupportedPayload { .. }) => continue,
129	            Err(error) => return Err(error),
130	        }
131	    }
132	    Err(EmbeddedModuleError::NoModules)
133	}
134	
135	fn load_bundle(
136	    ctx: &Arc<CudaContext>,
137	    bundle: &OwnedArtifactBundle,
138	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
139	    if let Some(cubin) = bundle.payload(ArtifactPayloadKind::Cubin) {
140	        return Ok(ctx.load_module_from_image(cubin)?);
141	    }
142	
143	    if let Some(ptx) = bundle.payload(ArtifactPayloadKind::Ptx) {
144	        return Ok(ctx.load_module_from_image(ptx)?);
145	    }
146	
147	    if let Some(nvvm_ir) = bundle.payload(ArtifactPayloadKind::NvvmIr) {
148	        let emitted = target_arch_for_bundle(bundle)?;
149	        let execution = ltoir::execution_arch_for_context(ctx)?;
150	        let image = match ltoir::execution_route(&emitted, &execution)? {
151	            ltoir::ExecutionRoute::Cubin => {
152	                ltoir::build_cubin_from_nvvm_ir(nvvm_ir, &bundle.name, &emitted.sm())?
153	            }
154	            ltoir::ExecutionRoute::PtxBridge => {
155	                ltoir::build_ptx_from_nvvm_ir(nvvm_ir, &bundle.name, &emitted.sm())?
156	            }
157	        };
158	        return Ok(ctx.load_module_from_image(&image)?);
159	    }
160	
161	    if let Some(ltoir) = bundle.payload(ArtifactPayloadKind::Ltoir) {
162	        let emitted = target_arch_for_bundle(bundle)?;
163	        let execution = ltoir::execution_arch_for_context(ctx)?;
164	        let image = match ltoir::execution_route(&emitted, &execution)? {
165	            ltoir::ExecutionRoute::Cubin => {
166	                ltoir::link_ltoir_to_cubin(ltoir, &bundle.name, &emitted.sm())?
167	            }
168	            ltoir::ExecutionRoute::PtxBridge => {
169	                ltoir::link_ltoir_to_ptx(ltoir, &bundle.name, &emitted.sm())?
170	            }
171	        };
172	        return Ok(ctx.load_module_from_image(&image)?);
173	    }
174	
175	    Err(EmbeddedModuleError::UnsupportedPayload {
176	        name: bundle.name.clone(),
177	    })
178	}
179	
180	fn target_arch_for_bundle(
181	    bundle: &OwnedArtifactBundle,
182	) -> Result<libnvvm_sys::CudaArch, ltoir::LtoirError> {
183	    let explicit = std::env::var("CUDA_OXIDE_TARGET").ok();
184	    target_arch_for_bundle_with_explicit(bundle, explicit.as_deref())
185	}
186	
187	fn target_arch_for_bundle_with_explicit(
188	    bundle: &OwnedArtifactBundle,
189	    explicit_target: Option<&str>,
190	) -> Result<libnvvm_sys::CudaArch, ltoir::LtoirError> {
191	    ltoir::resolve_source_target(concrete_bundle_target(&bundle.target)?, explicit_target)
192	}
193	
194	fn concrete_bundle_target(
195	    target: &str,
196	) -> Result<Option<libnvvm_sys::CudaArch>, ltoir::LtoirError> {
197	    match target {
198	        // Compatibility for artifacts emitted before concrete NVVM targets
199	        // were recorded. New bundles must never use these sentinels.
200	        "libdevice" | "nvvm-ir" => Ok(None),
201	        target => Ok(Some(target.parse()?)),
202	    }
203	}
204	
205	#[cfg(test)]
206	mod tests {
207	    use super::*;
208	
209	    fn bundle_with_target(target: &str) -> OwnedArtifactBundle {
210	        OwnedArtifactBundle {
211	            name: "demo".to_string(),
212	            target: target.to_string(),
213	            payloads: Vec::new(),
214	            entries: Vec::new(),
215	        }
216	    }
217	
218	    #[test]
219	    fn target_arch_uses_bundle_sm_target() {
220	        assert_eq!(
221	            concrete_bundle_target("sm_90")
222	                .unwrap()
223	                .map(|target| target.sm()),
224	            Some("sm_90".to_string())
225	        );
226	    }
227	
228	    #[test]
229	    fn target_arch_uses_bundle_compute_target() {
230	        assert_eq!(
231	            concrete_bundle_target("compute_90")
232	                .unwrap()
233	                .map(|target| target.sm()),
234	            Some("sm_90".to_string())
235	        );
236	    }
237	
238	    #[test]
239	    fn target_arch_falls_back_for_non_arch_target() {
240	        // Older bundles used these names instead of recording a concrete
241	        // architecture. New bundles always record a validated `sm_*` target.
242	        for legacy in ["libdevice", "nvvm-ir"] {
243	            assert_eq!(concrete_bundle_target(legacy).unwrap(), None);
244	        }
245	    }
246	
247	    #[test]
248	    fn legacy_bundle_without_recorded_target_requires_explicit_target() {
249	        for sentinel in ["libdevice", "nvvm-ir"] {
250	            let bundle = bundle_with_target(sentinel);
251	            let error = target_arch_for_bundle_with_explicit(&bundle, None)
252	                .expect_err("the original build target is required");
253	            assert!(matches!(error, ltoir::LtoirError::TargetNotFound));
254	
255	            let asserted =
256	                target_arch_for_bundle_with_explicit(&bundle, Some("compute_86")).unwrap();
257	            assert_eq!(asserted.sm(), "sm_86");
258	        }
259	    }
260	
261	    #[test]
262	    fn recorded_bundle_target_overrides_explicit_environment_target() {
263	        let bundle = bundle_with_target("sm_90");
264	        let selected = target_arch_for_bundle_with_explicit(&bundle, Some("sm_120")).unwrap();
265	        assert_eq!(selected.sm(), "sm_90");
266	    }
267	
268	    #[test]
269	    fn target_arch_rejects_malformed_bundle_target() {
270	        assert!(concrete_bundle_target("sm_90x").is_err());
271	    }
272	}
