4	 */
5	
6	//! Loading CUDA modules from embedded device artifact bundles.
7	
8	use crate::{CudaContext, CudaModule, DriverError};
9	use oxide_artifacts::ArtifactError;
10	pub use oxide_artifacts::{ArtifactPayloadKind, OwnedArtifactBundle};
11	use std::fmt;
12	use std::path::{Path, PathBuf};
13	use std::sync::Arc;
14	
15	#[derive(Clone, Debug, PartialEq, Eq)]
16	pub struct EmbeddedModule {
17	    bundle: OwnedArtifactBundle,
18	}
19	
20	impl EmbeddedModule {
21	    pub fn new(bundle: OwnedArtifactBundle) -> Option<Self> {
22	        loadable_payload(&bundle)
23	            .is_some()
24	            .then_some(Self { bundle })
25	    }
26	
27	    pub fn name(&self) -> &str {
28	        &self.bundle.name
29	    }
30	
31	    pub fn target(&self) -> &str {
32	        &self.bundle.target
33	    }
34	
35	    pub fn bundle(&self) -> &OwnedArtifactBundle {
36	        &self.bundle
37	    }
38	
39	    pub fn payload(&self, kind: ArtifactPayloadKind) -> Option<&[u8]> {
40	        self.bundle.payload(kind)
41	    }
42	
43	    pub fn load(&self, ctx: &Arc<CudaContext>) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
44	        let image =
45	            loadable_payload(&self.bundle).expect("EmbeddedModule always has a loadable payload");
46	        ctx.load_module_from_image(image)
47	            .map_err(EmbeddedModuleError::Driver)
48	    }
49	}
50	
51	pub fn artifact_bundles_from_current_exe() -> Result<Vec<OwnedArtifactBundle>, EmbeddedModuleError>
52	{
53	    let path =
54	        std::env::current_exe().map_err(|source| EmbeddedModuleError::CurrentExe { source })?;
55	    artifact_bundles_from_binary_path(path)
56	}
57	
58	pub fn artifact_bundles_from_binary_path(
59	    path: impl AsRef<Path>,
60	) -> Result<Vec<OwnedArtifactBundle>, EmbeddedModuleError> {
61	    let path = path.as_ref();
62	    let bytes = std::fs::read(path).map_err(|source| EmbeddedModuleError::Io {
63	        path: path.to_path_buf(),
64	        source,
65	    })?;
66	    oxide_artifacts::read_artifact_bundles_from_object_bytes(&bytes)
67	        .map_err(EmbeddedModuleError::Artifacts)
68	}
69	
70	pub fn embedded_modules_from_current_exe() -> Result<Vec<EmbeddedModule>, EmbeddedModuleError> {
71	    Ok(artifact_bundles_from_current_exe()?
72	        .into_iter()
73	        .filter_map(EmbeddedModule::new)
74	        .collect())
75	}
76	
77	pub fn load_embedded_module(
78	    ctx: &Arc<CudaContext>,
79	    name: &str,
80	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
81	    let module = embedded_modules_from_current_exe()?
82	        .into_iter()
83	        .find(|module| module.name() == name)
84	        .ok_or_else(|| EmbeddedModuleError::ModuleNotFound {
85	            name: name.to_string(),
86	        })?;
87	    module.load(ctx)
88	}
89	
90	pub fn load_first_embedded_module(
91	    ctx: &Arc<CudaContext>,
92	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
93	    let module = embedded_modules_from_current_exe()?
