287	pub fn build_artifact_blob(spec: &ArtifactBundleSpec<'_>) -> Result<Vec<u8>, ArtifactError> {
288	    validate_spec(spec)?;
289	
290	    let mut out = vec![0; HEADER_BYTES];
291	    push_bytes(&mut out, spec.name.as_bytes());
292	    push_bytes(&mut out, spec.target.as_bytes());
293	
294	    let payload_record_start = out.len();
295	    out.resize(out.len() + spec.payloads.len() * PAYLOAD_RECORD_BYTES, 0);
296	    let entry_record_start = out.len();
297	    out.resize(out.len() + spec.entries.len() * ENTRY_RECORD_BYTES, 0);
298	
299	    for (index, payload) in spec.payloads.iter().enumerate() {
300	        let name_offset = checked_u32(out.len(), "payload name offset")?;
301	        push_bytes(&mut out, payload.name.as_bytes());
302	        align_vec(&mut out, 8);
303	        let data_offset = checked_u32(out.len(), "payload data offset")?;
304	        push_bytes(&mut out, payload.bytes);
305	        align_vec(&mut out, 8);
306	
307	        let record = payload_record_start + index * PAYLOAD_RECORD_BYTES;
308	        write_u16(&mut out, record, payload.kind.to_u16());
309	        write_u16(&mut out, record + 2, 0);
310	        write_u32(&mut out, record + 4, data_offset);
311	        write_u32(
312	            &mut out,
313	            record + 8,
314	            checked_u32(payload.bytes.len(), "payload length")?,
315	        );
316	        write_u32(&mut out, record + 12, name_offset);
317	        write_u16(
318	            &mut out,
319	            record + 16,
320	            checked_u16(payload.name.len(), "payload name length")?,
321	        );
322	    }
323	
324	    for (index, entry) in spec.entries.iter().enumerate() {
325	        let symbol_offset = checked_u32(out.len(), "entry symbol offset")?;
326	        push_bytes(&mut out, entry.symbol.as_bytes());
327	        align_vec(&mut out, 8);
328	
329	        let record = entry_record_start + index * ENTRY_RECORD_BYTES;
330	        write_u16(&mut out, record, entry.kind.to_u16());
331	        write_u16(&mut out, record + 2, u16::from(entry.metadata.is_some()));
332	        write_u64(&mut out, record + 4, entry.metadata.unwrap_or(0));
333	        write_u32(&mut out, record + 12, symbol_offset);
334	        write_u16(
335	            &mut out,
336	            record + 16,
337	            checked_u16(entry.symbol.len(), "entry symbol length")?,
338	        );
339	    }
340	
341	    let total_len = checked_u32(out.len(), "total length")?;
342	    out[0..8].copy_from_slice(&ARTIFACT_MAGIC);
343	    write_u16(&mut out, 8, ARTIFACT_VERSION);
344	    write_u16(&mut out, 10, HEADER_BYTES as u16);
345	    write_u32(&mut out, 12, total_len);
346	    write_u16(&mut out, 16, checked_u16(spec.name.len(), "name length")?);
347	    write_u16(
348	        &mut out,
349	        18,
350	        checked_u16(spec.target.len(), "target length")?,
351	    );
352	    write_u16(
353	        &mut out,
354	        20,
355	        checked_u16(spec.payloads.len(), "payload count")?,
356	    );
357	    write_u16(
358	        &mut out,
359	        22,
360	        checked_u16(spec.entries.len(), "entry count")?,
361	    );
362	
363	    Ok(out)
364	}
