366	pub fn parse_artifact_section(mut bytes: &[u8]) -> Result<Vec<ArtifactBundle<'_>>, ArtifactError> {
367	    let mut bundles = Vec::new();
368	    while !bytes.is_empty() {
369	        if bytes.iter().all(|byte| *byte == 0) {
370	            break;
371	        }
372	        let total_len = artifact_blob_total_len(bytes)?;
373	        let (blob, rest) = bytes.split_at(total_len);
374	        bundles.push(parse_artifact_blob(blob)?);
375	        bytes = rest;
376	    }
377	    Ok(bundles)
378	}
