380	pub fn parse_artifact_blob(bytes: &[u8]) -> Result<ArtifactBundle<'_>, ArtifactError> {
381	    require_len(bytes, HEADER_BYTES, "header")?;
382	    if bytes[0..8] != ARTIFACT_MAGIC {
383	        return Err(ArtifactError::BadMagic);
384	    }
385	    let version = read_u16(bytes, 8)?;
386	    if version != ARTIFACT_VERSION {
387	        return Err(ArtifactError::UnsupportedVersion(version));
388	    }
389	    let header_len = read_u16(bytes, 10)? as usize;
390	    if header_len != HEADER_BYTES {
391	        return Err(ArtifactError::Malformed(format!(
392	            "unsupported embedded artifact header length {header_len}"
393	        )));
394	    }
395	    let total_len = read_u32(bytes, 12)? as usize;
396	    if total_len < HEADER_BYTES {
397	        return Err(ArtifactError::Malformed(format!(
398	            "embedded artifact length {total_len} is smaller than the header"
399	        )));
400	    }
401	    if total_len > bytes.len() {
402	        return Err(ArtifactError::Truncated("blob"));
403	    }
404	    let bytes = &bytes[..total_len];
405	    let name_len = read_u16(bytes, 16)? as usize;
406	    let target_len = read_u16(bytes, 18)? as usize;
407	    let payload_count = read_u16(bytes, 20)? as usize;
408	    let entry_count = read_u16(bytes, 22)? as usize;
409	
410	    let mut cursor = HEADER_BYTES;
411	    let name = read_str(bytes, cursor, name_len, "bundle name")?;
412	    cursor += name_len;
413	    let target = read_str(bytes, cursor, target_len, "target")?;
414	    cursor += target_len;
415	
416	    let payload_records = cursor;
417	    cursor = cursor
418	        .checked_add(payload_count * PAYLOAD_RECORD_BYTES)
419	        .ok_or(ArtifactError::TooLarge("payload records"))?;
420	    require_len(bytes, cursor, "payload records")?;
421	    let entry_records = cursor;
422	    cursor = cursor
423	        .checked_add(entry_count * ENTRY_RECORD_BYTES)
424	        .ok_or(ArtifactError::TooLarge("entry records"))?;
425	    require_len(bytes, cursor, "entry records")?;
426	
427	    let mut payloads = Vec::with_capacity(payload_count);
428	    for index in 0..payload_count {
429	        let record = payload_records + index * PAYLOAD_RECORD_BYTES;
430	        let kind_raw = read_u16(bytes, record)?;
431	        let kind = ArtifactPayloadKind::from_u16(kind_raw)
432	            .ok_or(ArtifactError::UnsupportedPayloadKind(kind_raw))?;
433	        let data_offset = read_u32(bytes, record + 4)? as usize;
434	        let data_len = read_u32(bytes, record + 8)? as usize;
435	        let name_offset = read_u32(bytes, record + 12)? as usize;
436	        let name_len = read_u16(bytes, record + 16)? as usize;
437	        let name = read_str(bytes, name_offset, name_len, "payload name")?;
438	        let data = read_slice(bytes, data_offset, data_len, "payload data")?;
439	        payloads.push(ArtifactPayload {
440	            kind,
441	            name,
442	            bytes: data,
443	        });
444	    }
445	
446	    let mut entries = Vec::with_capacity(entry_count);
447	    for index in 0..entry_count {
448	        let record = entry_records + index * ENTRY_RECORD_BYTES;
449	        let kind_raw = read_u16(bytes, record)?;
450	        let kind = ArtifactEntryKind::from_u16(kind_raw)
451	            .ok_or(ArtifactError::UnsupportedEntryKind(kind_raw))?;
452	        let flags = read_u16(bytes, record + 2)?;
453	        let metadata = if flags & 1 != 0 {
454	            Some(read_u64(bytes, record + 4)?)
455	        } else {
456	            None
457	        };
458	        let symbol_offset = read_u32(bytes, record + 12)? as usize;
459	        let symbol_len = read_u16(bytes, record + 16)? as usize;
460	        let symbol = read_str(bytes, symbol_offset, symbol_len, "entry symbol")?;
461	        entries.push(ArtifactEntry {
462	            symbol,
463	            kind,
464	            metadata,
465	        });
466	    }
467	
468	    Ok(ArtifactBundle {
469	        name,
470	        target,
471	        payloads,
472	        entries,
473	    })
474	}
