476	pub fn artifact_blob_total_len(bytes: &[u8]) -> Result<usize, ArtifactError> {
477	    require_len(bytes, HEADER_BYTES, "header")?;
478	    if bytes[0..8] != ARTIFACT_MAGIC {
479	        return Err(ArtifactError::BadMagic);
480	    }
481	    let total_len = read_u32(bytes, 12)? as usize;
482	    if total_len < HEADER_BYTES {
483	        return Err(ArtifactError::Malformed(format!(
484	            "embedded artifact length {total_len} is smaller than the header"
485	        )));
486	    }
487	    if total_len > bytes.len() {
488	        return Err(ArtifactError::Truncated("blob"));
489	    }
490	    Ok(total_len)
491	}
