494	pub fn read_artifact_bundles_from_object_bytes(
495	    bytes: &[u8],
496	) -> Result<Vec<OwnedArtifactBundle>, ArtifactError> {
497	    use object::{Object, ObjectSection};
498	
499	    let file = object::File::parse(bytes).map_err(|e| ArtifactError::Object(e.to_string()))?;
500	    let mut bundles = Vec::new();
501	    for section in file.sections() {
502	        let name = section
503	            .name()
504	            .map_err(|e| ArtifactError::Object(e.to_string()))?;
505	        if name != ARTIFACT_SECTION_NAME {
506	            continue;
507	        }
508	        let data = section
509	            .data()
510	            .map_err(|e| ArtifactError::Object(e.to_string()))?;
511	        bundles.extend(parse_artifact_section(data)?.into_iter().map(Into::into));
512	    }
513	    Ok(bundles)
514	}
