516	/// Wrap an artifact section blob in a relocatable host object file.
517	///
518	/// The object contains a single `.oxart` data section. When
519	/// `anchor_symbol` is given, a global symbol with that name is defined at
520	/// the start of the section. The anchor matters for *library* crates:
521	/// their artifact object becomes a member of an `.rlib` archive, and a
522	/// linker only extracts an archive member when the member defines a
523	/// symbol that resolves an outstanding undefined reference. Without a
524	/// defined symbol the member is silently skipped and the bundle never
525	/// reaches the final binary. Host-side code (the `#[cuda_module]` macro)
526	/// emits a matching reference to the anchor to force the extraction.
527	/// `SHF_GNU_RETAIN` on the section additionally protects it from
528	/// `--gc-sections` once the member has been linked in.
529	#[cfg(feature = "object-write")]
530	pub fn build_host_object_for_target(
531	    section_data: &[u8],
532	    target: &str,
533	    anchor_symbol: Option<&str>,
534	) -> Result<Vec<u8>, ArtifactError> {
535	    if section_data.is_empty() {
536	        return Err(ArtifactError::EmptyPayload);
537	    }
538	
539	    match anchor_symbol {
540	        Some(anchor_symbol) => build_host_object_with_section(
541	            ARTIFACT_SECTION_NAME,
542	            section_data,
543	            target,
544	            &[(anchor_symbol, false)],
545	        ),
546	        None => build_host_object_with_section(ARTIFACT_SECTION_NAME, section_data, target, &[]),
547	    }
548	}
