550	/// Wrap an artifact blob with a target-specific anchor and a weak legacy alias.
551	///
552	/// New owner-filter-aware macros reference the target-specific symbol. The
553	/// weak package-level alias keeps older macro expansions link-compatible while
554	/// avoiding duplicate-symbol failures when one package has several targets.
555	#[cfg(feature = "object-write")]
556	pub fn build_host_object_for_target_with_legacy_anchor(
557	    section_data: &[u8],
558	    target: &str,
559	    anchor_symbol: &str,
560	    legacy_anchor_symbol: &str,
561	) -> Result<Vec<u8>, ArtifactError> {
562	    if section_data.is_empty() {
563	        return Err(ArtifactError::EmptyPayload);
564	    }
565	    build_host_object_with_section(
566	        ARTIFACT_SECTION_NAME,
567	        section_data,
568	        target,
569	        &[(anchor_symbol, false), (legacy_anchor_symbol, true)],
570	    )
571	}
