573	/// Build a host object that only defines an artifact link-anchor symbol.
574	///
575	/// The CUDA backend uses this when an owner filter deliberately suppresses a
576	/// crate's device artifact. Older `#[cuda_module]` expansions can still
577	/// contain the legacy anchor reference, so the linker needs a matching weak
578	/// definition even though no `.oxart` section should be embedded. Keeping the
579	/// placeholder in a separate section means artifact discovery correctly sees
580	/// no device bundle.
581	#[cfg(feature = "object-write")]
582	pub fn build_host_anchor_object_for_target(
583	    target: &str,
584	    anchor_symbol: &str,
585	) -> Result<Vec<u8>, ArtifactError> {
586	    if anchor_symbol.is_empty() {
587	        return Err(ArtifactError::Malformed(
588	            "embedded artifact anchor symbol is empty".to_string(),
589	        ));
590	    }
591	
592	    build_host_object_with_section(
593	        ARTIFACT_ANCHOR_SECTION_NAME,
594	        &[0],
595	        target,
596	        &[(anchor_symbol, true)],
597	    )
598	}
