600	#[cfg(feature = "object-write")]
601	fn build_host_object_with_section(
602	    section_name: &str,
603	    section_data: &[u8],
604	    target: &str,
605	    anchor_symbols: &[(&str, bool)],
606	) -> Result<Vec<u8>, ArtifactError> {
607	    use object::write::{Object, Symbol, SymbolSection};
608	    use object::{SectionFlags, SectionKind, SymbolFlags, SymbolKind, SymbolScope};
609	
610	    let target = HostObjectTarget::parse(target)?;
611	    let mut object = Object::new(target.format, target.architecture, target.endianness);
612	    let section_id = object.add_section(
613	        Vec::new(),
614	        section_name.as_bytes().to_vec(),
615	        SectionKind::Data,
616	    );
617	    let section = object.section_mut(section_id);
618	    section.set_data(section_data.to_vec(), 8);
619	    section.flags = SectionFlags::Elf {
620	        sh_flags: elf::SHF_ALLOC | elf::SHF_GNU_RETAIN,
621	    };
622	
623	    for (anchor_symbol, weak) in anchor_symbols {
624	        // Global binding so the symbol can satisfy undefined references
625	        // from other objects (that is what triggers archive extraction);
626	        // `Linkage` scope so it stays hidden and never leaks into the
627	        // dynamic symbol table of the final binary.
628	        object.add_symbol(Symbol {
629	            name: anchor_symbol.as_bytes().to_vec(),
630	            value: 0,
631	            size: 0,
632	            kind: SymbolKind::Data,
633	            scope: SymbolScope::Linkage,
634	            weak: *weak,
635	            section: SymbolSection::Section(section_id),
636	            flags: SymbolFlags::None,
637	        });
638	    }
639	
640	    object
641	        .write()
642	        .map_err(|e| ArtifactError::Object(e.to_string()))
643	}
