645	#[cfg(feature = "object-write")]
646	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
647	struct HostObjectTarget {
648	    format: object::BinaryFormat,
649	    architecture: object::Architecture,
650	    endianness: object::Endianness,
651	}
652	
653	#[cfg(feature = "object-write")]
654	impl HostObjectTarget {
655	    fn parse(target: &str) -> Result<Self, ArtifactError> {
656	        let target = target.to_ascii_lowercase();
657	        let (architecture, endianness) = if target.starts_with("x86_64")
658	            || target.starts_with("amd64")
659	            || target.starts_with("x86-64")
660	        {
661	            (object::Architecture::X86_64, object::Endianness::Little)
662	        } else if target.starts_with("aarch64") || target.starts_with("arm64") {
663	            (object::Architecture::Aarch64, object::Endianness::Little)
664	        } else {
665	            return Err(ArtifactError::UnsupportedHostTarget(target));
666	        };
667	
668	        let format = if target.contains("linux") {
669	            object::BinaryFormat::Elf
670	        } else {
671	            return Err(ArtifactError::UnsupportedHostTarget(target));
672	        };
673	
674	        Ok(Self {
675	            format,
676	            architecture,
677	            endianness,
678	        })
679	    }
680	}
