688	fn validate_spec(spec: &ArtifactBundleSpec<'_>) -> Result<(), ArtifactError> {
689	    if spec.name.is_empty() {
690	        return Err(ArtifactError::EmptyBundleName);
691	    }
692	    if spec.target.is_empty() {
693	        return Err(ArtifactError::EmptyTarget);
694	    }
695	    if spec.payloads.is_empty() {
696	        return Err(ArtifactError::EmptyPayload);
697	    }
698	    for payload in &spec.payloads {
699	        if payload.name.is_empty() {
700	            return Err(ArtifactError::EmptyPayloadName);
701	        }
702	        if payload.bytes.is_empty() {
703	            return Err(ArtifactError::EmptyPayload);
704	        }
705	    }
706	    for entry in &spec.entries {
707	        if entry.symbol.is_empty() {
708	            return Err(ArtifactError::EmptyEntrySymbol);
709	        }
710	    }
711	    Ok(())
712	}
