733	fn read_slice<'a>(
734	    bytes: &'a [u8],
735	    offset: usize,
736	    len: usize,
737	    field: &'static str,
738	) -> Result<&'a [u8], ArtifactError> {
739	    let end = offset
740	        .checked_add(len)
741	        .ok_or(ArtifactError::TooLarge(field))?;
742	    bytes
743	        .get(offset..end)
744	        .ok_or(ArtifactError::Truncated(field))
745	}
