748	    bytes: &'a [u8],
749	    offset: usize,
750	    len: usize,
751	    field: &'static str,
752	) -> Result<&'a str, ArtifactError> {
753	    let bytes = read_slice(bytes, offset, len, field)?;
754	    core::str::from_utf8(bytes).map_err(|_| ArtifactError::InvalidUtf8(field))
